import anthropic

client = anthropic.Anthropic()

# Define the tools available to the agent
tools = [
    {
        "name": "write_file",
        "description": "Write content to a file on the local filesystem",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {
                    "type": "string",
                    "description": "Absolute path to the file to write"
                },
                "content": {
                    "type": "string", 
                    "description": "The content to write to the file"
                },
                "mode": {
                    "type": "string",
                    "enum": ["create", "overwrite", "append"],
                    "description": "Write mode: create (fail if exists), overwrite, or append",
                    "default": "overwrite"
                }
            },
            "required": ["path", "content"]
        }
    },
    {
        "name": "run_command",
        "description": "Execute a bash command and return stdout/stderr",
        "input_schema": {
            "type": "object",
            "properties": {
                "command": {"type": "string", "description": "The bash command to run"},
                "working_dir": {"type": "string", "description": "Working directory for the command"},
                "timeout_seconds": {"type": "integer", "default": 30}
            },
            "required": ["command"]
        }
    }
]

def execute_tool(tool_name: str, tool_input: dict) -> str:
    """Execute the requested tool and return the result as a string."""
    import subprocess, os

    if tool_name == "write_file":
        mode_map = {"create": "x", "overwrite": "w", "append": "a"}
        mode = mode_map.get(tool_input.get("mode", "overwrite"), "w")
        with open(tool_input["path"], mode) as f:
            f.write(tool_input["content"])
        return f"Successfully wrote {len(tool_input['content'])} bytes to {tool_input['path']}"

    elif tool_name == "run_command":
        result = subprocess.run(
            tool_input["command"],
            shell=True,
            cwd=tool_input.get("working_dir"),
            capture_output=True,
            text=True,
            timeout=tool_input.get("timeout_seconds", 30)
        )
        output = result.stdout
        if result.returncode != 0:
            output += f"\nSTDERR: {result.stderr}\nExit code: {result.returncode}"
        return output or "(no output)"

    return f"Unknown tool: {tool_name}"

def run_action_loop(task: str, max_turns: int = 20) -> str:
    """Run the agent action loop until completion or max turns reached."""
    messages = [{"role": "user", "content": task}]

    for turn in range(max_turns):
        response = client.messages.create(
            model="claude-sonnet-4-5",
            max_tokens=4096,
            tools=tools,
            messages=messages
        )

        # Append assistant response
        messages.append({"role": "assistant", "content": response.content})

        # Check if we are done
        if response.stop_reason == "end_turn":
            # Extract final text response
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return "Task completed."

        if response.stop_reason == "tool_use":
            # Execute all requested tools
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = execute_tool(block.name, block.input)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result
                    })

            # Append tool results and continue
            messages.append({"role": "user", "content": tool_results})

    return f"Reached max_turns ({max_turns}) without completing the task."

import asyncio
import anthropic

async def execute_tool_async(tool_name: str, tool_input: dict) -> str:
    """Async version of tool execution for parallel processing."""
    import aiofiles, asyncio

    if tool_name == "read_file":
        async with aiofiles.open(tool_input["path"], "r") as f:
            return await f.read()
    elif tool_name == "web_fetch":
        import aiohttp
        async with aiohttp.ClientSession() as session:
            async with session.get(tool_input["url"]) as resp:
                return await resp.text()
    return f"Unknown tool: {tool_name}"

async def run_parallel_tools(tool_use_blocks: list) -> list:
    """Execute multiple independent tool calls in parallel."""
    tasks = [
        execute_tool_async(block.name, block.input)
        for block in tool_use_blocks
        if block.type == "tool_use"
    ]
    results = await asyncio.gather(*tasks, return_exceptions=True)

    tool_results = []
    for block, result in zip(tool_use_blocks, results):
        if block.type != "tool_use":
            continue
        if isinstance(result, Exception):
            content = f"Tool execution failed: {result}"
        else:
            content = result
        tool_results.append({
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": content
        })
    return tool_results
